import json
from datetime import datetime

import modal
from fastapi import FastAPI

app = modal.App("modal-event-pipeline")

image = modal.Image.debian_slim().pip_install("fastapi")

queue = modal.Queue.from_name("modal-event-pipeline-queue", create_if_missing=True)
volume = modal.Volume.from_name("modal-event-pipeline-vol", create_if_missing=True)
output_dict = modal.Dict.from_name("modal-event-pipeline-output", create_if_missing=True)


@app.function(image=image)
def produce_events() -> int:
    events = []
    for event_id in range(10):
        events.append(
            {
                "event_id": event_id,
                "timestamp": datetime.utcnow().isoformat(),
                "payload": f"synthetic event payload {event_id}",
            }
        )

    queue.put_many(events)
    return len(events)


@app.function(image=image, volumes={"/events": volume})
def consume_events() -> int:
    processed_events = []

    while True:
        batch = queue.get_many(10, timeout=1)
        if not batch:
            break

        for event in batch:
            payload = event.get("payload", "")
            processed_events.append(
                {
                    **event,
                    "processed": True,
                    "word_count": len(payload.split()),
                }
            )

    output_path = "/events/processed_events.json"
    with open(output_path, "w", encoding="utf-8") as handle:
        json.dump(processed_events, handle, indent=2)

    volume.commit()
    return len(processed_events)


web_app = FastAPI()


@web_app.get("/")
async def get_status() -> dict:
    keys = [
        "events_produced",
        "events_consumed",
        "processing_complete",
        "output_path",
    ]
    return {key: output_dict.get(key) for key in keys}


@app.function(image=image)
@modal.asgi_app()
def status_endpoint():
    return web_app


@app.local_entrypoint()
def main() -> None:
    produced = produce_events.remote()
    consumed = consume_events.remote()

    output_dict["events_produced"] = produced
    output_dict["events_consumed"] = consumed
    output_dict["processing_complete"] = "true"
    output_dict["output_path"] = "/events/processed_events.json"

